import restrictedpython
import asyncio
from contextlib import asynccontextmanager

class SandboxResult(BaseModel):
    output: str
    error: str | None
    passed: bool

@tool
async def execute_sandbox(code: str, timeout: int = 5) -> SandboxResult:
    @asynccontextmanager
    async def sandbox_exec(code_str: str):
        try:
            # RestrictedPython safe globals
            safe_globals = restrictedpython.safe_globals.copy()
            safe_globals['print'] = print
            exec(code_str, safe_globals)
            yield "Execution completed"
        except Exception as e:
            yield f"Error: {str(e)}"

    try:
        result = await asyncio.wait_for(sandbox_exec(code), timeout=timeout)
        return SandboxResult(output=result, error=None, passed=True)
    except asyncio.TimeoutError:
        return SandboxResult(output="", error="Timeout", passed=False)

import ast
import re
from typing import List

class ValidationResult(BaseModel):
    tests_passed: int
    tests_total: int
    security_issues: List[str]
    valid: bool

DANGEROUS_PATTERNS = [
    r'api_key|secret|password',
    r'exec\(|eval\(',
    r'__import__',
    r'os\.system',
    r'subprocess\.call'
]

@tool
def validate_code(code: str, test_cases: List[str]) -> ValidationResult:
    # Security scan
    security_issues = []
    for pattern in DANGEROUS_PATTERNS:
        if re.search(pattern, code, re.IGNORECASE):
            security_issues.append(f"Detected: {pattern}")

    # AST syntax validation
    try:
        ast.parse(code)
    except SyntaxError as e:
        return ValidationResult(tests_passed=0, tests_total=0, security_issues=[str(e)], valid=False)

    # Test execution (simplified)
    tests_passed = sum(1 for test in test_cases if "pass" in test.lower())

    return ValidationResult(
        tests_passed=tests_passed,
        tests_total=len(test_cases),
        security_issues=security_issues,
        valid=not security_issues and tests_passed == len(test_cases)
    )

class CodeGenOrchestrator(BaseModel):
    final_code: str
    iterations: int
    success: bool

async def run_code_pipeline(requirements: str) -> CodeGenOrchestrator:
    agent = Agent(tools=[generate_code, execute_sandbox, validate_code])

    for iteration in range(5):  # Max 5 iterations
        result = await agent.run(f"""
        Generate code for: {requirements}
        Previous feedback: {get_feedback()}
        Ensure: valid syntax, passes tests, no security issues
        """)

        sandbox_result = await execute_sandbox(result.code)
        validation_result = await validate_code(result.code, ["test_functionality()"])

        if validation_result.valid:
            return CodeGenOrchestrator(
                final_code=result.code,
                iterations=iteration + 1,
                success=True
            )

    return CodeGenOrchestrator(final_code="", iterations=5, success=False)

