from vex_sdk import VexCheck, CheckResult

@vex_sdk.check(name="codegen.credential_leak")
async def detect_credentials(code: str) -> CheckResult:
    patterns = [
        r'(?i)(api[_-]?key|secret|password|token)=["\']?[a-zA-Z0-9]{20,}',
        r'Bearer\s+[a-zA-Z0-9._-]+',
        r'AIza[0-9A-Za-z_\-]{35}'
    ]

    issues = []
    for pattern in patterns:
        matches = re.finditer(pattern, code)
        for match in matches:
            issues.append({
                'type': 'credential',
                'pattern': pattern,
                'location': match.span(),
                'severity': 'critical'
            })

    if issues:
        return CheckResult(
            passed=False,
            issues=issues,
            remediation="Remove hardcoded credentials, use environment variables"
        )
    return CheckResult(passed=True)
